<script setup lang="ts">
import { onMounted, ref } from 'vue'; import { useRouter } from 'vue-router'; import { agentRequest, uploadForm } from '../../services/agentApi';
const router=useRouter();const tasks=ref<any[]>([]);const files=ref<File[]>([]);const taskName=ref('');const error=ref('');const creating=ref(false);const dragging=ref(false);
onMounted(load);async function load(){try{tasks.value=await agentRequest('/tasks');error.value=''}catch(e){error.value=message(e)}}
function select(list:FileList|null){if(!list)return;const seen=new Set(files.value.map(f=>`${f.name}:${f.size}`));for(const file of Array.from(list))if(file.type==='application/pdf'||file.name.toLowerCase().endsWith('.pdf')){const key=`${file.name}:${file.size}`;if(!seen.has(key)){files.value.push(file);seen.add(key)}}}
function drop(e:DragEvent){dragging.value=false;select(e.dataTransfer?.files||null)}
async function create(){if(!files.value.length)return;creating.value=true;error.value='';try{const task=await agentRequest<any>('/tasks',{method:'POST',body:uploadForm(files.value,{taskName:taskName.value||'机场 AIP AD-2 自主识别'})});await router.push(`/agent-tasks/${task.taskId}/upload`)}catch(e){error.value=message(e)}finally{creating.value=false}}
function message(e:unknown){return e instanceof Error?e.message:String(e)}
</script>
<template><main class="page"><header><div><p class="eyebrow">AIRPORT PROCEDURE INTELLIGENCE</p><h1>机场自主识别任务</h1><p>以机场为单位管理文件、程序包、识别计划与最终结果。</p></div></header><p v-if="error" class="error">{{error}}</p><section class="create"><div class="copy"><h2>上传机场 AIP AD-2 文件</h2><p>可以上传一个 PDF，也可以上传同一机场的多个 PDF 文件。系统会统一分析全部文件并自动划分飞行程序包。</p><input v-model="taskName" placeholder="任务名称（可选）"></div><div class="drop" :class="{dragging}" @dragover.prevent="dragging=true" @dragleave="dragging=false" @drop.prevent="drop"><strong>拖拽 PDF 或选择文件</strong><span>支持多选与文件夹</span><div><label>选择 PDF<input type="file" accept="application/pdf" multiple @change="select(($event.target as HTMLInputElement).files)"></label><label class="secondary">选择文件夹<input type="file" accept="application/pdf" multiple webkitdirectory="" @change="select(($event.target as HTMLInputElement).files)"></label></div></div><div v-if="files.length" class="queue"><div v-for="(file,index) in files" :key="file.name+file.size"><span>PDF</span><p><b>{{file.name}}</b><small>{{(file.size/1024/1024).toFixed(1)}} MB</small></p><button @click="files.splice(index,1)">移除</button></div><button class="primary" :disabled="creating" @click="create">{{creating?'正在创建…':`创建机场任务（${files.length} 个文件）`}}</button></div></section><section class="tasks"><div class="section-title"><h2>识别任务</h2><button @click="load">刷新</button></div><div v-if="tasks.length" class="task-list"><article v-for="task in tasks" :key="task.taskId"><div><span class="status">{{task.stage}}</span><h3>{{task.taskName}}</h3><p>{{task.airport?.icao||'机场待识别'}} · {{task.fileCount}} 个 PDF · {{task.packageCount}} 个程序包</p></div><div class="numbers"><b>{{task.recognizedCount}} / {{task.packageCount}}</b><small>已识别</small></div><button class="enter" @click="router.push(task.stage==='UPLOAD'?`/agent-tasks/${task.taskId}/upload`:task.stage==='PACKAGES_READY'||task.stage==='RECOGNIZING'?`/agent-tasks/${task.taskId}/packages`:`/agent-tasks/${task.taskId}/packages`)">进入任务</button></article></div><p v-else class="empty">暂无机场识别任务</p></section></main></template>
<style scoped>.page{padding:34px;max-width:1320px;margin:auto;color:#102a43}.eyebrow{font-size:12px;letter-spacing:.15em;color:#1769e0;font-weight:700}h1{font-size:34px;margin:4px 0}header p{color:#627d98}.error{background:#fee2e2;color:#991b1b;padding:12px;border-radius:8px}.create{margin-top:24px;background:#fff;border-radius:16px;padding:28px;box-shadow:0 8px 30px #102a4310;display:grid;grid-template-columns:.8fr 1.2fr;gap:28px}.copy p{color:#627d98;line-height:1.7}.copy input{width:100%;box-sizing:border-box;padding:11px;border:1px solid #ccd6e0;border-radius:8px}.drop{border:2px dashed #b8c7d9;border-radius:14px;min-height:190px;display:grid;place-content:center;text-align:center;gap:8px;background:#f8fbff}.drop.dragging{border-color:#1769e0;background:#edf5ff}.drop span{color:#829ab1}.drop label{display:inline-block;background:#1769e0;color:#fff;padding:9px 14px;border-radius:8px;margin:8px 4px;cursor:pointer}.drop label.secondary{background:#fff;color:#174ea6;border:1px solid #aac4e6}.drop input{display:none}.queue{grid-column:1/-1}.queue>div{display:flex;align-items:center;border-top:1px solid #edf1f5;padding:10px}.queue>div>span{background:#e8f1ff;color:#174ea6;padding:7px;border-radius:6px}.queue p{flex:1;margin:0 12px}.queue small{display:block;color:#829ab1}.queue button,.section-title button{border:0;background:none;color:#52606d;cursor:pointer}.primary,.enter{border:0;background:#1769e0;color:#fff;border-radius:8px;padding:11px 16px;cursor:pointer}.tasks{margin-top:34px}.section-title{display:flex;justify-content:space-between}.task-list{display:grid;gap:12px}.task-list article{display:flex;align-items:center;background:#fff;border-radius:12px;padding:18px 22px}.task-list h3{margin:5px 0}.task-list p{color:#627d98;margin:0}.status{font-size:11px;color:#1769e0;background:#edf5ff;padding:4px 7px;border-radius:5px}.numbers{text-align:center;margin-left:auto;margin-right:25px}.numbers b,.numbers small{display:block}.numbers small{color:#829ab1}.empty{text-align:center;color:#829ab1;padding:40px}@media(max-width:800px){.create{grid-template-columns:1fr}.page{padding:18px}.task-list article{align-items:flex-start;flex-wrap:wrap}.enter{margin-top:12px}}</style>
